import { Injectable, Logger } from "@nestjs/common";

import { DKGatewayException } from "../../exceptions/dk-gateway.exception.ts";
import { PaymentFailedException } from "../../exceptions/payment-failed.exception.ts";
import { TransactionRestrictionException } from "../../exceptions/transaction-restriction.exception.ts";
import { PaymentConfigService } from "../payment-config.service.ts";
import { DK_API_ENDPOINTS } from "./dk-api-endpoints.ts";
import { DKClientService } from "./dk-client.service.ts";
import { DK_RESPONSE_CODES } from "./dk-response-codes.ts";
import type {
  DKInitiateTransactionRequest,
  DKInitiateTransactionResponse,
  DKTransactionStatusRequest,
  DKTransactionStatusResponse,
} from "./dk-transfer-response.interface.ts";

export interface InitiatePaymentParams {
  inquiryId: string;
  amount: number;
  sourceAccountNumber: string;
  sourceAccountName: string;
  description: string;
}

export interface InitiateRefundParams {
  amount: number;
  targetAccountNumber: string;
  targetAccountName: string;
  targetCid: string;
  description: string;
}

export interface PaymentStatusResult {
  status: string;
  statusDescription: string;
  amount?: string;
  debitAccount?: string;
  creditAccount?: string;
  txnTimestamp?: string;
  txnStatusId?: string;
}

@Injectable()
export class DKTransferService {
  private readonly logger = new Logger(DKTransferService.name);

  constructor(
    private readonly dkClient: DKClientService,
    private readonly configService: PaymentConfigService,
  ) {}

  async initiatePayment(
    params: InitiatePaymentParams,
  ): Promise<{ inquiryId: string; txnStatusId: string }> {
    try {
      this.logger.log(
        `Initiating payment: ${params.amount} BTN from ${params.sourceAccountNumber}`,
      );

      const request: Omit<DKInitiateTransactionRequest, "request_id"> = {
        inquiry_id: params.inquiryId,
        transaction_datetime: new Date()
          .toISOString()
          .replace(/\.\d{3}Z$/, "Z"),
        source_app: this.configService.sourceApp,
        transaction_amount: params.amount.toFixed(2),
        currency: "BTN",
        payment_type: "INTRA",
        source_account_name: params.sourceAccountName,
        source_account_number: params.sourceAccountNumber,
        bene_cust_name: "National Day Lottery",
        bene_account_number: this.configService.beneficiaryAccount,
        bene_bank_code: this.configService.bankCode,
        narration: params.description,
      };

      const response = await this.dkClient.post<DKInitiateTransactionResponse>(
        DK_API_ENDPOINTS.TRANSACTION.INITIATE,
        request,
      );

      if (response.response_code !== DK_RESPONSE_CODES.SUCCESS) {
        this.logger.error(response);
        // Special handling for code 2008: Transaction restriction
        if (response.response_code === "2008") {
          throw new TransactionRestrictionException(
            response.response_description ||
              "Payment declined due to transaction restrictions on your bank account.",
          );
        }

        throw new DKGatewayException(
          response.response_code,
          response.response_message || "Transaction failed",
          response.response_description,
        );
      }

      if (!response.response_data) {
        throw new PaymentFailedException("No transaction data returned");
      }

      this.logger.log(
        `Payment initiated successfully. TxnStatusId: ${response.response_data.txn_status_id}`,
      );

      return {
        inquiryId: response.response_data.inquiry_id,
        txnStatusId: response.response_data.txn_status_id,
      };
    } catch (error) {
      this.logger.error("Failed to initiate payment", error);
      throw error;
    }
  }

  async initiateRefund(
    params: InitiateRefundParams,
  ): Promise<{ inquiryId: string; txnStatusId: string }> {
    try {
      this.logger.log(
        `Initiating refund: ${params.amount} BTN to ${params.targetAccountNumber} (CID: ${params.targetCid})`,
      );

      // First, get account inquiry for the target account
      const accountInquiryRequest = {
        account_number: params.targetAccountNumber,
      };

      const inquiryResponse = await this.dkClient.post<any>(
        DK_API_ENDPOINTS.ACCOUNT.INQUIRY,
        accountInquiryRequest,
      );

      if (inquiryResponse.response_code !== DK_RESPONSE_CODES.SUCCESS) {
        throw new DKGatewayException(
          inquiryResponse.response_code,
          inquiryResponse.response_message || "Account inquiry failed",
          inquiryResponse.response_description,
        );
      }

      const inquiryId = inquiryResponse.response_data.inquiry_id;

      // Now initiate the refund transfer FROM public account TO user account
      const refundRequest: Omit<DKInitiateTransactionRequest, "request_id"> = {
        inquiry_id: inquiryId,
        transaction_datetime: new Date()
          .toISOString()
          .replace(/\.\d{3}Z$/, "Z"),
        source_app: this.configService.sourceApp,
        transaction_amount: params.amount.toFixed(2),
        currency: "BTN",
        payment_type: "INTRA",
        source_account_name: "National Day Lottery", // Public account name
        source_account_number: this.configService.publicAccount, // FROM public account
        bene_cust_name: params.targetAccountName, // TO user account
        bene_account_number: params.targetAccountNumber, // TO user account
        bene_bank_code: this.configService.bankCode,
        narration: params.description,
      };

      const response = await this.dkClient.post<DKInitiateTransactionResponse>(
        DK_API_ENDPOINTS.TRANSACTION.INITIATE,
        refundRequest,
      );

      if (response.response_code !== DK_RESPONSE_CODES.SUCCESS) {
        throw new DKGatewayException(
          response.response_code,
          response.response_message || "Refund failed",
          response.response_description,
        );
      }

      if (!response.response_data) {
        throw new PaymentFailedException("No refund transaction data returned");
      }

      this.logger.log(
        `Refund initiated successfully. TxnStatusId: ${response.response_data.txn_status_id}`,
      );

      return {
        inquiryId: response.response_data.inquiry_id,
        txnStatusId: response.response_data.txn_status_id,
      };
    } catch (error) {
      this.logger.error("Failed to initiate refund", error);
      throw error;
    }
  }

  async checkPaymentStatus(
    transactionId: string,
  ): Promise<PaymentStatusResult> {
    try {
      this.logger.log(`Checking payment status for: ${transactionId}`);

      const request: Omit<DKTransactionStatusRequest, "request_id"> = {
        transaction_id: transactionId,
        bene_account_number: this.configService.beneficiaryAccount,
      };

      const response = await this.dkClient.post<DKTransactionStatusResponse>(
        DK_API_ENDPOINTS.TRANSACTION.STATUS,
        request,
      );

      if (response.response_code !== DK_RESPONSE_CODES.SUCCESS) {
        if (response.response_code === DK_RESPONSE_CODES.NOT_FOUND) {
          return {
            status: "PENDING",
            statusDescription:
              "Transaction not found - may be processed on next business day",
          };
        }

        throw new DKGatewayException(
          response.response_code,
          response.response_message || "Transaction status check failed",
          response.response_description || "Unknown error",
        );
      }

      if (!response.response_data) {
        return {
          status: "PENDING",
          statusDescription: "Transaction status not available",
        };
      }

      const statusData = response.response_data.status;

      return {
        status: statusData.status,
        statusDescription: statusData.status_desc,
        amount: statusData.amount,
        debitAccount: statusData.debit_account,
        creditAccount: statusData.credit_account,
        txnTimestamp: statusData.txn_ts,
      };
    } catch (error) {
      this.logger.error(
        `Failed to check payment status for: ${transactionId}`,
        error,
      );
      throw error;
    }
  }
}
